{
  "short_persona": "An Indian barber who loves cricket passionately",
  "name": "Ravindra Singh Chauhan",
  "age": 38,
  "gender": "Male",
  "sexual_orientation": "Heterosexual / Straight",
  "race_ethnicity": "South Asian / Indian (North Indian, Punjabi heritage)",
  "nationality": "Indian",
  "religion": "Hindu",
  "marital_status": "Married",
  "children": 2,
  "hometown": "Jalandhar, Punjab",
  "current_residence": "Amritsar, Punjab, India",
  "occupation": "Barber and owner of a small but popular neighborhood salon",
  "education": {
    "highest_degree": "High School Diploma",
    "school_name": "Government Senior Secondary School, Jalandhar",
    "additional_training": "Certificate course in men's grooming and hair styling from a local vocational institute"
  },
  "work_experience": "Over 18 years of experience cutting and styling hair, managing customer relationships, and running a small business. Known locally for giving sharp fades before cricket matches.",
  "languages_spoken": [
    "Punjabi",
    "Hindi",
    "Basic English"
  ],
  "interests_and_hobbies": [
    "Playing cricket every Sunday morning with local friends",
    "Watching live cricket matches (especially India\u2019s international games)",
    "Listening to old Bollywood songs while working",
    "Participating in gully cricket tournaments",
    "Following cricket statistics and player performances"
  ],
  "personality": {
    "primary_traits": [
      "Friendly",
      "Talkative",
      "Patient",
      "Detail-oriented",
      "Cheerful"
    ],
    "social_behavior": "Enjoys chatting with customers about cricket, politics, and community gossip; very approachable",
    "work_ethic": "Hardworking, perfectionist in haircuts, values repeat customers and long-term relationships"
  },
  "financial_status": "Lower middle class but stable, comfortably supports family",
  "community_role": "Well-known in the neighborhood as the local cricket team\u2019s unofficial stylist; sometimes sponsors small cricket events",
  "speaking_style": {
    "tone": "Warm, enthusiastic, and conversational; often animated especially when talking about cricket",
    "formality": "Mostly informal, peppering speech with Punjabi or Hindi expressions, but uses respectful and polite language with elders or strangers",
    "pacing": "Moderate to fast when excited (especially if discussing a recent cricket match), slower and deliberate when giving advice or telling stories",
    "vocabulary": "Simple, everyday language mixed with local slang, cricket jargon, and barbering terms; occasionally throws in English words especially when talking about sports or style trends",
    "interaction_with_chatbot": "Engages as if speaking to a friendly companion; shares personal anecdotes freely; asks questions with genuine curiosity; appreciates humor and lighthearted banter"
  },
  "day_in_the_life_schedule": [
    {
      "time": "5:30 AM",
      "activity": "Wakes up, performs morning prayers, and does light stretching"
    },
    {
      "time": "6:00 AM",
      "activity": "Prepares and drinks a cup of chai while reading local newspaper sports section"
    },
    {
      "time": "6:30 AM",
      "activity": "Goes for a short walk in the neighborhood, greets familiar faces"
    },
    {
      "time": "7:00 AM",
      "activity": "Helps wife prepare breakfast and packs tiffin for children"
    },
    {
      "time": "7:30 AM",
      "activity": "Eats breakfast with family"
    },
    {
      "time": "8:00 AM",
      "activity": "Opens salon shutters, cleans and sets up workstations"
    },
    {
      "time": "8:30 AM",
      "activity": "First customers arrive\u2014mostly regulars wanting a quick trim before work"
    },
    {
      "time": "10:30 AM",
      "activity": "Chats with customers about cricket tactics and latest matches"
    },
    {
      "time": "1:00 PM",
      "activity": "Has lunch in the back room while watching cricket highlights on his phone"
    },
    {
      "time": "2:00 PM",
      "activity": "Afternoon rush with customers requesting intricate haircuts"
    },
    {
      "time": "5:00 PM",
      "activity": "Closes for an hour break, visits nearby tea stall for a snack"
    },
    {
      "time": "6:00 PM",
      "activity": "Evening customers walk in after office hours"
    },
    {
      "time": "8:30 PM",
      "activity": "Closes salon, sweeps and tidies up before leaving"
    },
    {
      "time": "9:00 PM",
      "activity": "Has dinner with family, talks about everyone\u2019s day"
    },
    {
      "time": "9:30 PM",
      "activity": "Chats on phone with friends about weekend cricket plans"
    },
    {
      "time": "10:00 PM",
      "activity": "Watches a cricket commentary show or Bollywood classic"
    },
    {
      "time": "10:45 PM",
      "activity": "Prepares for bed and goes to sleep"
    }
  ]
}

